import { PROVIDER_DISPLAY } from "@repo/app-providers/client";
import type {
  GraphContext,
  SoftwareApplication,
  WebPage,
} from "@vendor/seo/json-ld";
import type { IntegrationPageData } from "~/lib/content-schemas";
import type { IntegrationUrl } from "~/lib/url-types";
import {
  buildBreadcrumbList,
  buildFaqEntity,
  buildOrganizationEntity,
  buildWebSiteEntity,
} from "./shared";

function buildIntegrationPageEntity(
  data: IntegrationPageData,
  url: IntegrationUrl
): Omit<WebPage, "@id" | "url"> {
  return {
    "@type": "WebPage",
    name: data.title,
    description: data.description,
    dateModified: data.updatedAt,
    inLanguage: "en-US",
    isPartOf: { "@id": "https://lightfast.ai/#website" },
    publisher: { "@id": "https://lightfast.ai/#organization" },
    ...(data.providerId
      ? { about: { "@id": `${url}#integrated-app` } }
      : {}),
    keywords: data.keywords.join(", "),
  };
}

function buildIntegratedAppEntity(
  data: IntegrationPageData,
  url: IntegrationUrl
): SoftwareApplication | null {
  if (!data.providerId) return null;
  const display = PROVIDER_DISPLAY[data.providerId];
  return {
    "@type": "SoftwareApplication",
    "@id": `${url}#integrated-app`,
    name: display.displayName,
    description: display.description,
    applicationCategory: "DeveloperApplication",
    operatingSystem: "Web",
  };
}

export function buildIntegrationJsonLd(
  data: IntegrationPageData,
  url: IntegrationUrl
): GraphContext {
  const entity = buildIntegrationPageEntity(data, url);
  const integratedApp = buildIntegratedAppEntity(data, url);
  return {
    "@context": "https://schema.org",
    "@graph": [
      buildOrganizationEntity(),
      buildWebSiteEntity(),
      { ...entity, "@id": `${url}#webpage`, url },
      ...(integratedApp ? [integratedApp] : []),
      ...(data.faq && data.faq.length > 0
        ? [buildFaqEntity(data.faq, url)]
        : []),
      buildBreadcrumbList([
        { name: "Home", url: "https://lightfast.ai" },
        { name: "Integrations", url: "https://lightfast.ai/integrations" },
        { name: data.title, url },
      ]),
    ],
  };
}

import { IntegrationLogoIcons } from "@repo/ui/integration-icons";
import { UPCOMING_INTEGRATIONS } from "../_lib/upcoming-integrations";

export function UpcomingIntegrationsList() {
  return (
    <section className="mt-24">
      <div className="grid grid-cols-1 gap-8 lg:grid-cols-3 lg:gap-16">
        {/* Left: Badge */}
        <div>
          <span className="inline-flex h-7 items-center rounded-md border border-border px-3 text-muted-foreground text-sm">
            Roadmap
          </span>
        </div>

        {/* Right: Upcoming integrations - spans 2 columns */}
        <div className="lg:col-span-2">
          <div className="mb-8 flex items-baseline justify-between border-border border-b pb-8">
            <p className="text-base text-muted-foreground leading-relaxed md:text-lg">
              Upcoming integrations.
            </p>
            <span className="text-muted-foreground text-sm">
              {UPCOMING_INTEGRATIONS.length} planned
            </span>
          </div>

          <ul className="divide-y divide-border/50 overflow-hidden rounded-md border border-border/50 bg-accent/20">
            {UPCOMING_INTEGRATIONS.map((item) => {
              const Icon = IntegrationLogoIcons[item.id];
              return (
                <li
                  className="flex items-center gap-4 px-4 py-3 md:px-6"
                  key={item.id}
                >
                  <Icon
                    aria-hidden
                    className="size-4 shrink-0 text-foreground"
                  />
                  <div className="flex min-w-0 flex-1 items-baseline gap-3">
                    <span className="shrink-0 font-medium text-foreground text-sm">
                      {item.name}
                    </span>
                    <span className="truncate text-muted-foreground text-sm">
                      {item.description}
                    </span>
                  </div>
                  <span className="shrink-0 rounded-sm border border-border/50 bg-background px-2 py-0.5 text-muted-foreground text-xs">
                    Planned
                  </span>
                </li>
              );
            })}
          </ul>
        </div>
      </div>
    </section>
  );
}

